package derive

// XLayerAA (EIP-8130) network upgrade transactions.
//
// On the activation boundary block of `XLayerAATime`, the attributes
// builder emits 7 deposit transactions that install the EIP-8130 system
// contracts at canonical `CREATE(deployer, 0)` addresses. The 7
// (deployer, address) pairs are mirrored byte-identically in the
// xlayer-reth EL chainspec at:
//
//   crates/chainspec/src/xlayer_aa_predeploys.rs
//
// A unit test in this package + the Rust-side
// `create_address_matches_deployer` test guards both sides against
// drift.
//
// # Bytecode source
//
// Each `*DeploymentBytecode` constant below is the raw creation
// bytecode (constructor prelude + runtime + metadata) emitted by:
//
//   just contracts-eip8130-build
//
// (which runs `forge build` then extracts hex into
// `contracts/eip8130/artifacts/<Name>.bin-creation`). After
// regenerating those artifact files, paste the hex content into the
// matching `*DeploymentBytecode` constant in this file.
//
// Three of the contracts (`DefaultAccount`, `DefaultHighRateAccount`,
// `DelegateVerifier`) take the `AccountConfiguration` predeploy
// address as a single constructor arg. We append `abi.encode(addr)`
// (32-byte left-padded) to the raw creation bytecode for each of
// those before wrapping it into a `DepositTx.Data`. The on-chain
// constructor reads it from the end of calldata and writes it to the
// `ACCOUNT_CONFIGURATION` immutable.

import (
	"math/big"

	"github.com/ethereum/go-ethereum/common"
	"github.com/ethereum/go-ethereum/common/hexutil"
	"github.com/ethereum/go-ethereum/core/types"
)

// XLayerAA deployer addresses. Each is a fresh account whose nonce is
// guaranteed to be 0 at the activation boundary block, so
// `CREATE(deployer, 0)` produces a deterministic address that's
// identical across devnet / testnet / mainnet.
//
// MUST stay in sync with the `deployer` field of every entry in
// `AA_PREDEPLOYS` in `crates/chainspec/src/xlayer_aa_predeploys.rs`.
var (
	XLayerAAAccountConfigurationDeployerAddress   = common.HexToAddress("0x4210000000000000000000000000000000000010")
	XLayerAADefaultAccountDeployerAddress         = common.HexToAddress("0x4210000000000000000000000000000000000011")
	XLayerAADefaultHighRateAccountDeployerAddress = common.HexToAddress("0x4210000000000000000000000000000000000012")
	XLayerAAK1VerifierDeployerAddress             = common.HexToAddress("0x4210000000000000000000000000000000000013")
	XLayerAAP256VerifierDeployerAddress           = common.HexToAddress("0x4210000000000000000000000000000000000014")
	XLayerAAWebAuthnVerifierDeployerAddress       = common.HexToAddress("0x4210000000000000000000000000000000000015")
	XLayerAADelegateVerifierDeployerAddress       = common.HexToAddress("0x4210000000000000000000000000000000000016")
)

// XLayerAA predeploy addresses — the destinations users / dApps
// reference. Equal to `crypto.CreateAddress(deployer, 0)` for each
// corresponding deployer above.
//
// MUST stay in sync with the `address` field in
// `crates/chainspec/src/xlayer_aa_predeploys.rs`. The unit test
// `TestXLayerAAUpgradeTransactionsAddressesMatchCreateAddress` in
// this package re-derives every address from its deployer to catch
// any typo here.
var (
	XLayerAAAccountConfigurationAddress   = common.HexToAddress("0xA6A551b856B139B3292128F3b36ADa58025c4b27")
	XLayerAADefaultAccountAddress         = common.HexToAddress("0x5D82f4311f134052bb36b11BD665Ddab843ebb3D")
	XLayerAADefaultHighRateAccountAddress = common.HexToAddress("0x86bf4F2d426b3386a04a24fE21a0CEb34A7b806c")
	XLayerAAK1VerifierAddress             = common.HexToAddress("0x7F2c04d16c53f2be99aD1a86771637568B718dBf")
	XLayerAAP256VerifierAddress           = common.HexToAddress("0xAfc812351BE998FB088851a79Fc68887C42D7719")
	XLayerAAWebAuthnVerifierAddress       = common.HexToAddress("0x4921DCFD2541f738990767852aB925B3b9f652A2")
	XLayerAADelegateVerifierAddress       = common.HexToAddress("0xE89A62553fE775AFe77464969b2296dc1745CF85")
)

// Deposit-source intent strings. Hashed into `SourceHash` to give each
// upgrade tx a deterministic, unique identifier so the EL can dedup
// and operators can grep logs.
var (
	deployXLayerAAAccountConfigurationSource   = UpgradeDepositSource{Intent: "XLayerAA: AccountConfiguration Deployment"}
	deployXLayerAADefaultAccountSource         = UpgradeDepositSource{Intent: "XLayerAA: DefaultAccount Deployment"}
	deployXLayerAADefaultHighRateAccountSource = UpgradeDepositSource{Intent: "XLayerAA: DefaultHighRateAccount Deployment"}
	deployXLayerAAK1VerifierSource             = UpgradeDepositSource{Intent: "XLayerAA: K1Verifier Deployment"}
	deployXLayerAAP256VerifierSource           = UpgradeDepositSource{Intent: "XLayerAA: P256Verifier Deployment"}
	deployXLayerAAWebAuthnVerifierSource       = UpgradeDepositSource{Intent: "XLayerAA: WebAuthnVerifier Deployment"}
	deployXLayerAADelegateVerifierSource       = UpgradeDepositSource{Intent: "XLayerAA: DelegateVerifier Deployment"}
)

// Per-contract gas budgets. Derived from runtime sizes (the largest is
// AccountConfiguration at ~7.3KB) plus a generous safety margin for
// constructor execution and SSTORE costs. Each value is well below
// the upstream upgrade-tx gas budgets used by Ecotone/Isthmus/Jovian
// (e.g. 1.75M for Jovian's GPO), giving room for future Solidity
// growth without revisiting these numbers.
const (
	deployXLayerAAAccountConfigurationGas   = uint64(2_500_000)
	deployXLayerAADefaultAccountGas         = uint64(1_000_000)
	deployXLayerAADefaultHighRateAccountGas = uint64(1_000_000)
	deployXLayerAAK1VerifierGas             = uint64(750_000)
	deployXLayerAAP256VerifierGas           = uint64(1_500_000)
	deployXLayerAAWebAuthnVerifierGas       = uint64(2_000_000)
	deployXLayerAADelegateVerifierGas       = uint64(750_000)
)

// XLayerAANetworkUpgradeTransactions returns the 7 upgrade deposit
// transactions that install the EIP-8130 predeploys.
//
// Order matters: `AccountConfiguration` MUST be deployed first because
// `DefaultAccount`, `DefaultHighRateAccount`, and `DelegateVerifier`
// take its address as a constructor arg via the appended
// `abi.encode(XLayerAAAccountConfigurationAddress)` payload. Same
// ordering is enforced in the Rust-side `AA_PREDEPLOYS` table by the
// `account_configuration_is_first_entry` test.
func XLayerAANetworkUpgradeTransactions() ([]hexutil.Bytes, error) {
	upgradeTxns := make([]hexutil.Bytes, 0, 7)

	// 1. AccountConfiguration — no constructor args.
	deployAccountConfiguration, err := types.NewTx(&types.DepositTx{
		SourceHash:          deployXLayerAAAccountConfigurationSource.SourceHash(),
		From:                XLayerAAAccountConfigurationDeployerAddress,
		To:                  nil,
		Mint:                big.NewInt(0),
		Value:               big.NewInt(0),
		Gas:                 deployXLayerAAAccountConfigurationGas,
		IsSystemTransaction: false,
		Data:                accountConfigurationDeploymentBytecode,
	}).MarshalBinary()
	if err != nil {
		return nil, err
	}
	upgradeTxns = append(upgradeTxns, deployAccountConfiguration)

	// 2. DefaultAccount — constructor: (address accountConfiguration).
	deployDefaultAccount, err := types.NewTx(&types.DepositTx{
		SourceHash:          deployXLayerAADefaultAccountSource.SourceHash(),
		From:                XLayerAADefaultAccountDeployerAddress,
		To:                  nil,
		Mint:                big.NewInt(0),
		Value:               big.NewInt(0),
		Gas:                 deployXLayerAADefaultAccountGas,
		IsSystemTransaction: false,
		Data:                appendAccountConfigurationArg(defaultAccountDeploymentBytecode),
	}).MarshalBinary()
	if err != nil {
		return nil, err
	}
	upgradeTxns = append(upgradeTxns, deployDefaultAccount)

	// 3. DefaultHighRateAccount — constructor: (address accountConfiguration).
	deployDefaultHighRateAccount, err := types.NewTx(&types.DepositTx{
		SourceHash:          deployXLayerAADefaultHighRateAccountSource.SourceHash(),
		From:                XLayerAADefaultHighRateAccountDeployerAddress,
		To:                  nil,
		Mint:                big.NewInt(0),
		Value:               big.NewInt(0),
		Gas:                 deployXLayerAADefaultHighRateAccountGas,
		IsSystemTransaction: false,
		Data:                appendAccountConfigurationArg(defaultHighRateAccountDeploymentBytecode),
	}).MarshalBinary()
	if err != nil {
		return nil, err
	}
	upgradeTxns = append(upgradeTxns, deployDefaultHighRateAccount)

	// 4. K1Verifier — no constructor args.
	deployK1Verifier, err := types.NewTx(&types.DepositTx{
		SourceHash:          deployXLayerAAK1VerifierSource.SourceHash(),
		From:                XLayerAAK1VerifierDeployerAddress,
		To:                  nil,
		Mint:                big.NewInt(0),
		Value:               big.NewInt(0),
		Gas:                 deployXLayerAAK1VerifierGas,
		IsSystemTransaction: false,
		Data:                k1VerifierDeploymentBytecode,
	}).MarshalBinary()
	if err != nil {
		return nil, err
	}
	upgradeTxns = append(upgradeTxns, deployK1Verifier)

	// 5. P256Verifier — no constructor args.
	deployP256Verifier, err := types.NewTx(&types.DepositTx{
		SourceHash:          deployXLayerAAP256VerifierSource.SourceHash(),
		From:                XLayerAAP256VerifierDeployerAddress,
		To:                  nil,
		Mint:                big.NewInt(0),
		Value:               big.NewInt(0),
		Gas:                 deployXLayerAAP256VerifierGas,
		IsSystemTransaction: false,
		Data:                p256VerifierDeploymentBytecode,
	}).MarshalBinary()
	if err != nil {
		return nil, err
	}
	upgradeTxns = append(upgradeTxns, deployP256Verifier)

	// 6. WebAuthnVerifier — no constructor args.
	deployWebAuthnVerifier, err := types.NewTx(&types.DepositTx{
		SourceHash:          deployXLayerAAWebAuthnVerifierSource.SourceHash(),
		From:                XLayerAAWebAuthnVerifierDeployerAddress,
		To:                  nil,
		Mint:                big.NewInt(0),
		Value:               big.NewInt(0),
		Gas:                 deployXLayerAAWebAuthnVerifierGas,
		IsSystemTransaction: false,
		Data:                webAuthnVerifierDeploymentBytecode,
	}).MarshalBinary()
	if err != nil {
		return nil, err
	}
	upgradeTxns = append(upgradeTxns, deployWebAuthnVerifier)

	// 7. DelegateVerifier — constructor: (address accountConfiguration).
	deployDelegateVerifier, err := types.NewTx(&types.DepositTx{
		SourceHash:          deployXLayerAADelegateVerifierSource.SourceHash(),
		From:                XLayerAADelegateVerifierDeployerAddress,
		To:                  nil,
		Mint:                big.NewInt(0),
		Value:               big.NewInt(0),
		Gas:                 deployXLayerAADelegateVerifierGas,
		IsSystemTransaction: false,
		Data:                appendAccountConfigurationArg(delegateVerifierDeploymentBytecode),
	}).MarshalBinary()
	if err != nil {
		return nil, err
	}
	upgradeTxns = append(upgradeTxns, deployDelegateVerifier)

	return upgradeTxns, nil
}

// appendAccountConfigurationArg returns a copy of `creationCode` with
// `abi.encode(XLayerAAAccountConfigurationAddress)` (32-byte
// left-padded) appended. Used for the 3 contracts whose constructor
// is `(address accountConfiguration)`.
func appendAccountConfigurationArg(creationCode []byte) []byte {
	out := make([]byte, 0, len(creationCode)+32)
	out = append(out, creationCode...)
	out = append(out, common.LeftPadBytes(XLayerAAAccountConfigurationAddress.Bytes(), 32)...)
	return out
}

// ── EIP-8130 creation-code constants ───────────────────────────────
//
// Generated by `just contracts-eip8130-build` in the parent xlayer-reth
// repo; bytes are the `bytecode.object` field from each Foundry
// artifact in `contracts/eip8130/artifacts/<Name>.bin-creation`.
//
// Immutables in the runtime portion of the creation code remain as
// zero placeholders here — they're filled by the on-chain constructor
// when the deposit tx executes. For contracts with no constructor
// args (AccountConfiguration / K1Verifier / P256Verifier /
// WebAuthnVerifier), the bytecode is used as-is. For the other 3,
// `appendAccountConfigurationArg` adds the 32-byte AC address before
// the tx payload is built.

var accountConfigurationDeploymentBytecode = common.FromHex("")

var defaultAccountDeploymentBytecode = common.FromHex("")

var defaultHighRateAccountDeploymentBytecode = common.FromHex("")

var k1VerifierDeploymentBytecode = common.FromHex("")

var p256VerifierDeploymentBytecode = common.FromHex("")

var webAuthnVerifierDeploymentBytecode = common.FromHex("")

var delegateVerifierDeploymentBytecode = common.FromHex("")
